1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Array<Damage> };
5	type Step = { op: string; items?: Array<Item>; policy?: number; incident?: Incident };
6	type Scenario = { customer?: Customer; steps: Array<Step> };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT_RATE = 0.15;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	function withFirstInsuranceSurcharge(basePremium: number): number {
29	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
30	}
31	
32	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
33	  return condition ? basePremium * rate : 0;
34	}
35	
36	function quoteItem(item: Item): number {
37	  const basePremium = BASE_PREMIUMS[item.type];
38	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
39	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
40	  const highEnchantmentSurcharge = surchargeIf(
41	    isHighlyEnchanted,
42	    basePremium,
43	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
44	  );
45	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
46	}
47	
48	const COMPONENT_TYPES = ["rune", "moonstone"];
49	const BLOCK_OF_THREE_BASE = 60;
50	
51	function countByType(items: Array<Item>): Record<string, number> {
52	  const counts: Record<string, number> = {};
53	  for (const item of items) {
54	    counts[item.type] = (counts[item.type] ?? 0) + 1;
55	  }
56	  return counts;
57	}
58	
59	function isLoyalCustomer(customer: Customer | undefined): boolean {
60	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
61	}
62	
63	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
64	  const counts = countByType(items);
65	  let itemsPremium = 0;
66	  let sumOfBases = 0;
67	  const bundledTypes = new Set<string>();
68	
69	  for (const componentType of COMPONENT_TYPES) {
70	    if (counts[componentType] === 3) {
71	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
72	      sumOfBases += BLOCK_OF_THREE_BASE;
73	      bundledTypes.add(componentType);
74	    }
75	  }
76	
77	  for (const item of items) {
78	    if (bundledTypes.has(item.type)) continue;
79	    itemsPremium += quoteItem(item);
80	    sumOfBases += BASE_PREMIUMS[item.type];
81	  }
82	
83	  return { itemsPremium, sumOfBases };
84	}
85	
86	function computePayout(incident: Incident | undefined): number {
87	  const damages = incident?.damages ?? [];
88	  return damages.reduce(
89	    (total, damage) => total + Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE),
90	    0,
91	  );
92	}
93	
94	export function processScenario(
95	  scenario: unknown,
96	): { results: Array<{ premium?: number; payout?: number; remainingCap?: number }> } {
97	  const { customer, steps } = scenario as Scenario;
98	  const results: Array<{ premium?: number; payout?: number; remainingCap?: number }> = [];
99	
100	  for (const [stepIndex, step] of steps.entries()) {
101	    if (step.op === "claim") {
102	      results.push({ payout: computePayout(step.incident) });
103	      continue;
104	    }
105	
106	    let { itemsPremium, sumOfBases } = quoteItems(step.items ?? []);
107	
108	    if (isLoyalCustomer(customer)) {
109	      itemsPremium -= sumOfBases * LOYALTY_DISCOUNT_RATE;
110	    }
111	
112	    const isFollowUp = stepIndex >= 1;
113	    if (isFollowUp) {
114	      itemsPremium -= sumOfBases * FOLLOWUP_DISCOUNT_RATE;
115	    }
116	
117	    const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
118	    results.push({ premium });
119	  }
120	
121	  return { results };
122	}
